use std::f32::consts::PI;
use std::io::Write;
use std::process::{Command, Stdio};
use std::fs;

const WIDTH: usize = 160;
const HEIGHT: usize = 90;
const OUTPUT_WIDTH: usize = 3840;
const OUTPUT_HEIGHT: usize = 2160;
const TOTAL_FRAMES: usize = 6000; // 100s at 60fps (about 5s breathing x 20)
const FPS: usize = 60;
const BREATHING_PERIOD_FRAMES: usize = 300; // 5s at 60fps
const SAMPLE_RATE: usize = 44100;
const FRAME_HOP: usize = SAMPLE_RATE / FPS;

#[derive(Clone, Copy)]
struct Color {
    r: u8,
    g: u8,
    b: u8,
}

const CYAN: Color = Color {
    r: 0,
    g: 255,
    b: 255,
};
const MAGENTA: Color = Color {
    r: 255,
    g: 0,
    b: 255,
};
const GOLD: Color = Color {
    r: 255,
    g: 215,
    b: 0,
};
const WHITE: Color = Color {
    r: 255,
    g: 255,
    b: 255,
};

fn set_pixel(rgba: &mut [u8], x: f32, y: f32, color: Color, alpha: f32) {
    let ix = x.floor() as isize;
    let iy = y.floor() as isize;
    if ix < 0 || iy < 0 || ix >= WIDTH as isize || iy >= HEIGHT as isize {
        return;
    }
    let idx = ((iy as usize) * WIDTH + (ix as usize)) * 4;
    let inv_alpha = 1.0 - alpha;
    rgba[idx] = (rgba[idx] as f32 * inv_alpha + color.r as f32 * alpha).round() as u8;
    rgba[idx + 1] = (rgba[idx + 1] as f32 * inv_alpha + color.g as f32 * alpha).round() as u8;
    rgba[idx + 2] = (rgba[idx + 2] as f32 * inv_alpha + color.b as f32 * alpha).round() as u8;
    rgba[idx + 3] = 255;
}

fn add_glow(rgba: &mut [u8], x: f32, y: f32, color: Color, intensity: f32) {
    // Draw glow halo around point
    for dy in -2..=2 {
        for dx in -2..=2 {
            let nx = x + dx as f32;
            let ny = y + dy as f32;
            let dist = ((dx * dx + dy * dy) as f32).sqrt();
            if dist > 0.1 {
                let falloff = 1.0 / (1.0 + dist * dist);
                set_pixel(rgba, nx, ny, color, intensity * falloff * 0.3);
            }
        }
    }
}

struct AudioFeatures {
    energy: f32,        // RMS energy [0, 1]
    spectral_centroid: f32, // Brightness [0, 1] (normalized)
    zero_crossing_rate: f32, // Noise estimate [0, 1]
}

struct KnotParams {
    p: f32,
    q: f32,
    spread: f32,
    speed: f32,
    tail: f32,
    scale: f32,
}

fn compute_audio_features(samples: &[f32]) -> AudioFeatures {
    if samples.is_empty() {
        return AudioFeatures {
            energy: 0.0,
            spectral_centroid: 0.5,
            zero_crossing_rate: 0.0,
        };
    }

    // RMS energy
    let energy: f32 = samples.iter().map(|s| s * s).sum::<f32>() / samples.len() as f32;
    let energy = energy.sqrt().min(1.0);

    // Zero-crossing rate (noise indicator)
    let mut zero_crossings = 0;
    for i in 1..samples.len() {
        if (samples[i] >= 0.0) != (samples[i - 1] >= 0.0) {
            zero_crossings += 1;
        }
    }
    let zero_crossing_rate = (zero_crossings as f32 / samples.len() as f32).min(1.0);

    // Simplified spectral centroid via weighted magnitude
    let mut weighted_sum = 0.0;
    let mut mag_sum = 0.0;
    for (i, &sample) in samples.iter().enumerate() {
        let mag = sample.abs();
        weighted_sum += (i as f32) * mag;
        mag_sum += mag;
    }
    let spectral_centroid = if mag_sum > 0.0 {
        (weighted_sum / mag_sum / samples.len() as f32).min(1.0)
    } else {
        0.5
    };

    AudioFeatures {
        energy,
        spectral_centroid,
        zero_crossing_rate,
    }
}

fn compute_entrainment_params(
    frame: usize,
    seed: f32,
    audio_features: Option<&AudioFeatures>,
    fixed_p: Option<f32>,
    fixed_q: Option<f32>,
) -> KnotParams {
    let breath_phase = (frame % BREATHING_PERIOD_FRAMES) as f32 / BREATHING_PERIOD_FRAMES as f32;
    let t = frame as f32 * 0.016; // ~60fps timing
    let breathing = 1.0 + 0.25 * (breath_phase * 2.0 * PI).sin();

    // Audio-responsive modulation (if provided)
    let (audio_energy, audio_brightness, audio_motion) = if let Some(af) = audio_features {
        (af.energy, af.spectral_centroid, af.zero_crossing_rate)
    } else {
        (0.5, 0.5, 0.0)
    };

    // If fixed (p, q) provided, use them; otherwise compute dynamically
    let (p, q) = if let (Some(fp), Some(fq)) = (fixed_p, fixed_q) {
        // Fixed mode: use exact p, q with slight audio modulation for life
        let audio_blend = audio_energy * 0.1; // Subtle audio influence
        let p_mod = fp + (audio_energy - 0.5) * (0.5 + audio_blend);
        let q_mod = fq + (audio_motion - 0.5) * (0.3 + audio_blend);
        (p_mod, q_mod)
    } else {
        // Dynamic mode: Fibonacci-scaled cycling through parameters
        let phi = 1.618_034;
        let fib_cycle = ((t * 0.05 + seed) % (phi * phi)).sin();

        let audio_blend = audio_energy * 0.5;
        let blended_fib = fib_cycle * (1.0 - audio_blend) + audio_energy * audio_blend;

        let p = 2.5 + 2.5 * (blended_fib + audio_energy * 0.3).clamp(-1.0, 1.0);
        let q = 1.5 + 1.5 * (blended_fib.cos() + audio_motion * 0.2).clamp(-1.0, 1.0);
        (p, q)
    };

    let spread = 2.0 + 1.5 * ((audio_brightness * 0.5).sin()).clamp(-1.0, 1.0);
    let speed = 0.5 + 0.5 * ((audio_energy * PI).cos()).clamp(-1.0, 1.0);

    // Breathing modulated by audio energy (louder = more pronounced breathing)
    let audio_breathing = breathing * (0.8 + audio_energy * 0.4);
    let tail = 10.0 + 8.0 * audio_breathing + audio_energy * 4.0;
    let scale = audio_breathing * 15.0 + audio_energy * 5.0;

    KnotParams {
        p,
        q,
        spread,
        speed,
        tail,
        scale,
    }
}

fn render_knot_particles(
    rgba: &mut [u8],
    frame: usize,
    seed: f32,
    audio_features: Option<&AudioFeatures>,
    fixed_p: Option<f32>,
    fixed_q: Option<f32>,
) {
    let params = compute_entrainment_params(frame, seed, audio_features, fixed_p, fixed_q);
    let cx = WIDTH as f32 / 2.0;
    let cy = HEIGHT as f32 / 2.0;

    // Generate torus knot points
    let segments = 300;
    for i in 0..segments {
        let u = (i as f32 / segments as f32) * 2.0 * PI;

        // Torus knot: (p, q) = (3, 2) is trefoil; params modulate this
        let p_eff = params.p.round() as i32;
        let q_eff = params.q.round() as i32;
        let r = ((q_eff as f32 * u).cos() + 2.0) * (params.spread / 3.0);
        let x = r * (p_eff as f32 * u).cos();
        let y = r * (p_eff as f32 * u).sin();
        let z = (q_eff as f32 * u).sin();

        // Rotation with time
        let t = frame as f32 * params.speed * 0.01;
        let x_rot = x * t.cos() - z * t.sin();
        let z_rot = x * t.sin() + z * t.cos();
        let y_rot = y * (frame as f32 * 0.005).cos();

        // Project to 2D
        let scale = params.scale / (4.0 + z_rot * 0.5);
        let px = cx + x_rot * scale;
        let py = cy + y_rot * scale;

        if px >= 0.0 && px < WIDTH as f32 && py >= 0.0 && py < HEIGHT as f32 {
            // Particle color based on position in knot
            let hue_phase = u / (2.0 * PI);
            let color = if hue_phase < 0.33 {
                CYAN
            } else if hue_phase < 0.66 {
                MAGENTA
            } else {
                GOLD
            };

            // Core particle
            set_pixel(rgba, px, py, color, 0.9);

            // Glow halo
            add_glow(rgba, px, py, color, 0.6);

            // Particle trails (tail effect)
            for j in 1..params.tail.ceil() as i32 {
                let t_offset = (frame as i32 - j) as f32 * params.speed * 0.01;
                let trail_u = u - t_offset * 0.05;
                let trail_r = ((q_eff as f32 * trail_u).cos() + 2.0) * (params.spread / 3.0);
                let trail_x = trail_r * (p_eff as f32 * trail_u).cos();
                let trail_y = trail_r * (p_eff as f32 * trail_u).sin();
                let trail_z = (q_eff as f32 * trail_u).sin();

                let trail_x_rot = trail_x * t_offset.cos() - trail_z * t_offset.sin();
                let trail_z_rot = trail_x * t_offset.sin() + trail_z * t_offset.cos();
                let trail_y_rot = trail_y * (frame as f32 * 0.005).cos();

                let trail_scale = params.scale / (4.0 + trail_z_rot * 0.5);
                let trail_px = cx + trail_x_rot * trail_scale;
                let trail_py = cy + trail_y_rot * trail_scale;

                let fade = 1.0 - (j as f32 / params.tail);
                if trail_px >= 0.0 && trail_px < WIDTH as f32 && trail_py >= 0.0 && trail_py < HEIGHT as f32
                {
                    set_pixel(rgba, trail_px, trail_py, color, fade * fade * 0.5);
                }
            }
        }
    }

    // Render B5 strands (5 braided strands around the knot)
    for strand_idx in 0..5 {
        let strand_angle = (strand_idx as f32 / 5.0) * 2.0 * PI;
        for i in 0..segments {
            let u = (i as f32 / segments as f32) * 2.0 * PI;
            let p_eff = params.p.round() as i32;
            let q_eff = params.q.round() as i32;
            let r = ((q_eff as f32 * u).cos() + 2.0) * (params.spread / 3.0);

            // Offset strand from base knot
            let offset = 0.1 * params.spread * strand_angle.cos();
            let x = (r + offset) * (p_eff as f32 * u).cos();
            let y = (r + offset) * (p_eff as f32 * u).sin();
            let z = (q_eff as f32 * u).sin() + 0.2 * strand_angle.sin();

            let t = frame as f32 * params.speed * 0.01;
            let x_rot = x * t.cos() - z * t.sin();
            let z_rot = x * t.sin() + z * t.cos();
            let y_rot = y * (frame as f32 * 0.005).cos();

            let scale = params.scale / (4.0 + z_rot * 0.5);
            let px = cx + x_rot * scale;
            let py = cy + y_rot * scale;

            if px >= 0.0 && px < WIDTH as f32 && py >= 0.0 && py < HEIGHT as f32 {
                // B5 strand colors
                let strand_color = match strand_idx {
                    0 => CYAN,
                    1 => MAGENTA,
                    2 => GOLD,
                    3 => WHITE,
                    _ => Color { r: 100, g: 200, b: 255 },
                };
                set_pixel(rgba, px, py, strand_color, 0.6);
            }
        }
    }
}

fn upscale_4k(low_res: &[u8], high_res: &mut [u8]) {
    let scale_x = OUTPUT_WIDTH / WIDTH;
    let scale_y = OUTPUT_HEIGHT / HEIGHT;

    for y in 0..HEIGHT {
        for x in 0..WIDTH {
            let src_idx = (y * WIDTH + x) * 4;
            let r = low_res[src_idx];
            let g = low_res[src_idx + 1];
            let b = low_res[src_idx + 2];
            let a = low_res[src_idx + 3];

            for dy in 0..scale_y {
                for dx in 0..scale_x {
                    let out_x = x * scale_x + dx;
                    let out_y = y * scale_y + dy;
                    let out_idx = (out_y * OUTPUT_WIDTH + out_x) * 4;
                    high_res[out_idx] = r;
                    high_res[out_idx + 1] = g;
                    high_res[out_idx + 2] = b;
                    high_res[out_idx + 3] = a;
                }
            }
        }
    }
}

fn main() {
    let args: Vec<String> = std::env::args().collect();
    if args.len() < 3 {
        eprintln!("Usage: knot-viz-video <output.mp4> <seed>");
        eprintln!("       [--audio-file <path.pcm>] [--p <f32>] [--q <f32>] [--frames <usize>]");
        std::process::exit(1);
    }

    let output_path = &args[1];
    let seed: f32 = args.get(2).and_then(|s| s.parse().ok()).unwrap_or(42.0);

    // Parse optional parameters
    let audio_path = if let Some(pos) = args.iter().position(|x| x == "--audio-file") {
        args.get(pos + 1).map(String::as_str)
    } else {
        None
    };

    let fixed_p = if let Some(pos) = args.iter().position(|x| x == "--p") {
        args.get(pos + 1).and_then(|s| s.parse::<f32>().ok())
    } else {
        None
    };

    let fixed_q = if let Some(pos) = args.iter().position(|x| x == "--q") {
        args.get(pos + 1).and_then(|s| s.parse::<f32>().ok())
    } else {
        None
    };

    let total_frames = if let Some(pos) = args.iter().position(|x| x == "--frames") {
        args.get(pos + 1)
            .and_then(|s| s.parse::<usize>().ok())
            .unwrap_or(TOTAL_FRAMES)
    } else if fixed_p.is_some() && fixed_q.is_some() {
        300 // Single breathing cycle loop for fixed configs
    } else {
        TOTAL_FRAMES
    };

    // Load audio if provided
    let audio_data = audio_path.and_then(|path| {
        match fs::read(path) {
            Ok(buf) => {
                let f32_len = buf.len() / 4;
                let f32_array = unsafe {
                    std::slice::from_raw_parts(
                        buf.as_ptr() as *const f32,
                        f32_len,
                    ).to_vec()
                };
                eprintln!("Loaded {} samples from audio file", f32_len);
                Some(f32_array)
            }
            Err(e) => {
                eprintln!("Warning: Could not load audio file: {}", e);
                None
            }
        }
    });

    // Start ffmpeg process for H.264 encoding
    let mut ffmpeg = Command::new("ffmpeg")
        .args(&[
            "-f", "rawvideo",
            "-pix_fmt", "rgba",
            "-s", &format!("{}x{}", OUTPUT_WIDTH, OUTPUT_HEIGHT),
            "-r", &FPS.to_string(),
            "-i", "pipe:0",
            "-c:v", "libx264",
            "-preset", "fast",
            "-crf", "18",
            "-pix_fmt", "yuv420p",
            "-y",
            output_path,
        ])
        .stdin(Stdio::piped())
        .spawn()
        .expect("Failed to spawn ffmpeg");

    let mut stdin = ffmpeg.stdin.take().expect("Failed to open ffmpeg stdin");

    let mut low_res = vec![0u8; WIDTH * HEIGHT * 4];
    let mut high_res = vec![0u8; OUTPUT_WIDTH * OUTPUT_HEIGHT * 4];

    eprintln!(
        "Rendering {} frames ({}px, fixed_p={}, fixed_q={})...",
        total_frames,
        if fixed_p.is_some() { "loop" } else { "100s" },
        fixed_p.map(|p| format!("{:.2}", p)).unwrap_or_else(|| "dynamic".to_string()),
        fixed_q.map(|q| format!("{:.2}", q)).unwrap_or_else(|| "dynamic".to_string()),
    );

    for frame in 0..total_frames {
        if frame % 60 == 0 {
            eprintln!("  Frame {}/{}", frame, total_frames);
        }

        // Clear frame
        low_res.fill(0);

        // Extract audio features for this frame if audio is available
        let audio_features = audio_data.as_ref().map(|pcm| {
            let frame_start = frame * FRAME_HOP;
            let frame_end = (frame_start + FRAME_HOP).min(pcm.len());
            if frame_start < pcm.len() {
                compute_audio_features(&pcm[frame_start..frame_end])
            } else {
                AudioFeatures {
                    energy: 0.0,
                    spectral_centroid: 0.5,
                    zero_crossing_rate: 0.0,
                }
            }
        });

        // Render knot particles with B5 strands
        render_knot_particles(
            &mut low_res,
            frame,
            seed,
            audio_features.as_ref(),
            fixed_p,
            fixed_q,
        );

        // Upscale to 4K
        upscale_4k(&low_res, &mut high_res);

        // Write to ffmpeg
        stdin.write_all(&high_res).expect("Failed to write to ffmpeg");
    }

    drop(stdin);
    ffmpeg.wait().expect("ffmpeg failed");
    eprintln!("Saved to {}", output_path);
}
